        if (!intentValidation.isValid) {
            Log.e(TAG, "Intent validation failed: ${intentValidation.reason}")
            sendErrorCallback(intent, "INVALID_INTENT_DATA", intentValidation.reason)
            stopSelfIfIdle(startId)
            return START_NOT_STICKY
