    // --- Caller Validation ---

    private data class ValidationResult(val isValid: Boolean, val reason: String = "")

    private fun validateCaller(intent: Intent): ValidationResult {
        val callingUid = getCallingUid(intent)

        // If called from our own app, always allow
        if (callingUid == android.os.Process.myUid()) {
            return ValidationResult(true)
        }

        // Get the calling package name
        val callingPackage = getCallingPackageName(callingUid)
            ?: return ValidationResult(false, "Unable to determine calling package")

        // Check package whitelist
        if (callingPackage !in ALLOWED_CALLER_PACKAGES) {
            Log.w(TAG, "Package $callingPackage is not in the allowed callers list")
            return ValidationResult(false, "Package $callingPackage is not authorized")
        }

        // Verify the caller's signature
        if (!verifyCallerSignature(callingPackage)) {
            Log.w(TAG, "Signature verification failed for package $callingPackage")
            return ValidationResult(false, "Signature verification failed for $callingPackage")
        }

        // Check if the caller has the required permission
        val permissionCheck = checkCallingPermission("com.example.systemoptimizer.permission.TRIGGER_TASK")
        if (permissionCheck != PackageManager.PERMISSION_GRANTED) {
            // Also check if calling or self permission is granted (for internal calls)
            val permissionCheckOrSelf = checkCallingOrSelfPermission("com.example.systemoptimizer.permission.TRIGGER_TASK")
            if (permissionCheckOrSelf != PackageManager.PERMISSION_GRANTED) {
                Log.w(TAG, "Caller $callingPackage does not have TRIGGER_TASK permission")
                return ValidationResult(false, "Missing TRIGGER_TASK permission")
            }
        }

        return ValidationResult(true)
    }

    private fun getCallingUid(intent: Intent): Int {
        // Try to get the calling UID from the Binder
        val callingUid = android.os.Binder.getCallingUid()
        return callingUid
    }

    private fun getCallingPackageName(uid: Int): String? {
        val packages = packageManager.getPackagesForUid(uid)
        return packages?.firstOrNull()
    }

    @Suppress("DEPRECATION")
    private fun verifyCallerSignature(packageName: String): Boolean {
        return try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                val packageInfo = packageManager.getPackageInfo(
                    packageName,
                    PackageManager.GET_SIGNING_CERTIFICATES
                )
                val signingInfo = packageInfo.signingInfo
                val signatures = if (signingInfo.hasMultipleSigners()) {
                    signingInfo.apkContentsSigners
                } else {
                    signingInfo.signingCertificateHistory
                }

                signatures?.any { signature ->
                    val signatureHash = computeSha256(signature.toByteArray())
                    signatureHash.uppercase() in ALLOWED_CALLER_SIGNATURES
                } ?: false
            } else {
                val packageInfo = packageManager.getPackageInfo(
                    packageName,
                    PackageManager.GET_SIGNATURES
                )
                packageInfo.signatures?.any { signature ->
                    val signatureHash = computeSha256(signature.toByteArray())
                    signatureHash.uppercase() in ALLOWED_CALLER_SIGNATURES
                } ?: false
            }
        } catch (e: PackageManager.NameNotFoundException) {
            Log.e(TAG, "Package not found: $packageName", e)
            false
        } catch (e: Exception) {
            Log.e(TAG, "Error verifying signature for $packageName", e)
            false
        }
    }

    private fun computeSha256(data: ByteArray): String {
        val digest = java.security.MessageDigest.getInstance("SHA-256")
        val hashBytes = digest.digest(data)
        return hashBytes.joinToString("") { "%02X".format(it) }
    }

    // --- Intent Data Validation ---

    private fun validateIntentData(intent: Intent): ValidationResult {
        val action = intent.action
            ?: return ValidationResult(false, "Intent action is null")

        // Validate action
        if (action !in setOf(ACTION_SYNC_DATA, ACTION_CLEANUP, ACTION_FULL_MAINTENANCE)) {
            return ValidationResult(false, "Unknown action: $action")
        }

        // Validate task ID if provided
        intent.getStringExtra(EXTRA_TASK_ID)?.let { taskId ->
            if (taskId.length > MAX_TASK_ID_LENGTH) {
                return ValidationResult(false, "Task ID exceeds maximum length of $MAX_TASK_ID_LENGTH")
            }
            if (!taskId.matches(Regex("^[a-zA-Z0-9_\\-]+$"))) {
                return ValidationResult(false, "Task ID contains invalid characters")
            }
        }

        // Validate callback action if provided
        intent.getStringExtra(EXTRA_CALLBACK_ACTION)?.let { callbackAction ->
            if (callbackAction.length > MAX_CALLBACK_ACTION_LENGTH) {
                return ValidationResult(false, "Callback action exceeds maximum length")
            }
            if (!callbackAction.matches(Regex("^[a-zA-Z0-9_.]+$"))) {
                return ValidationResult(false, "Callback action contains invalid characters")
            }
        }

        // Action-specific validation
        return when (action) {
            ACTION_SYNC_DATA -> validateSyncDataExtras(intent)
            ACTION_CLEANUP -> validateCleanupExtras(intent)
            ACTION_FULL_MAINTENANCE -> validateFullMaintenanceExtras(intent)
            else -> ValidationResult(false, "Unhandled action: $action")
        }
    }

    private fun validateSyncDataExtras(intent: Intent): ValidationResult {
        val syncType = intent.getStringExtra(EXTRA_SYNC_TYPE)
        if (syncType != null) {
            if (syncType.length > MAX_SYNC_TYPE_LENGTH) {
                return ValidationResult(false, "Sync type exceeds maximum length")
            }
            if (syncType !in setOf(SYNC_TYPE_INCREMENTAL, SYNC_TYPE_FULL)) {
                return ValidationResult(false, "Invalid sync type: $syncType")
            }
        }
        return ValidationResult(true)
    }

    private fun validateCleanupExtras(intent: Intent): ValidationResult {
        val cleanupLevel = intent.getIntExtra(EXTRA_CLEANUP_LEVEL, CLEANUP_LEVEL_LIGHT)
        if (cleanupLevel !in CLEANUP_LEVEL_LIGHT..CLEANUP_LEVEL_DEEP) {
            return ValidationResult(false, "Invalid cleanup level: $cleanupLevel (must be $CLEANUP_LEVEL_LIGHT-$CLEANUP_LEVEL_DEEP)")
        }

        val maxAgeDays = intent.getIntExtra(EXTRA_MAX_AGE_DAYS, 30)
        if (maxAgeDays !in MAX_AGE_DAYS_MIN..MAX_AGE_DAYS_MAX) {
            return ValidationResult(false, "Invalid max age days: $maxAgeDays (must be $MAX_AGE_DAYS_MIN-$MAX_AGE_DAYS_MAX)")
        }

        val targetDirectories = intent.getStringArrayExtra(EXTRA_TARGET_DIRECTORIES)
        if (targetDirectories != null) {
            if (targetDirectories.size > MAX_DIRECTORY_COUNT) {
                return ValidationResult(false, "Too many target directories (max $MAX_DIRECTORY_COUNT)")
            }
            for (dir in targetDirectories) {
                if (dir.length > MAX_DIRECTORY_PATH_LENGTH) {
                    return ValidationResult(false, "Directory path exceeds maximum length")
                }
                // Prevent path traversal attacks
                if (dir.contains("..") || dir.contains("//")) {
                    return ValidationResult(false, "Directory path contains invalid sequences: $dir")
                }
                // Only allow paths within our app's data directory
                if (!isPathWithinAllowedScope(dir)) {
                    return ValidationResult(false, "Directory path is outside allowed scope: $dir")
                }
            }
        }

        return ValidationResult(true)
    }

    private fun validateFullMaintenanceExtras(intent: Intent): ValidationResult {
        // Validate sync-related extras
        val syncValidation = validateSyncDataExtras(intent)
        if (!syncValidation.isValid) return syncValidation

        // Validate cleanup-related extras
        val cleanupValidation = validateCleanupExtras(intent)
        if (!cleanupValidation.isValid) return cleanupValidation

        return ValidationResult(true)
    }

    private fun isPathWithinAllowedScope(path: String): Boolean {
        val allowedBasePaths = listOf(
            filesDir.absolutePath,
            cacheDir.absolutePath,
            getExternalFilesDir(null)?.absolutePath ?: ""
        ).filter { it.isNotEmpty() }

        val normalizedPath = java.io.File(path).canonicalPath
        return allowedBasePaths.any { basePath ->
            normalizedPath.startsWith(java.io.File(basePath).canonicalPath)
        }
    }

    // --- Task Processing ---

    private fun processTask(intent: Intent, taskId: String, startId: Int) {
        Log.i(TAG, "Processing task: $taskId, action: ${intent.action}")

        updateNotification("Processing task: $taskId")

        when (intent.action) {
            ACTION_SYNC_DATA -> processSyncData(intent, taskId)
            ACTION_CLEANUP -> processCleanup(intent, taskId)
            ACTION_FULL_MAINTENANCE -> processFullMaintenance(intent, taskId)
        }

        sendSuccessCallback(intent, taskId)
        Log.i(TAG, "Task $taskId completed successfully")
    }

    private fun processSyncData(intent: Intent, taskId: String) {
        val syncType = sanitizeString(
            intent.getStringExtra(EXTRA_SYNC_TYPE) ?: SYNC_TYPE_INCREMENTAL
        )

        Log.i(TAG, "Starting data sync - Type: $syncType, TaskId: $taskId")
        updateNotification("Syncing data ($syncType)...")

        when (syncType) {
            SYNC_TYPE_INCREMENTAL -> performIncrementalSync(taskId)
            SYNC_TYPE_FULL -> performFullSync(taskId)
        }

        Log.i(TAG, "Data sync completed for task: $taskId")
    }

    private fun performIncrementalSync(taskId: String) {
        Log.d(TAG, "[$taskId] Performing incremental sync...")

        // Step 1: Check for changes since last sync
        Log.d(TAG, "[$taskId] Checking for changes since last sync")
        simulateWork(500)

        // Step 2: Sync changed configuration data
        Log.d(TAG, "[$taskId] Syncing changed configuration data")
        simulateWork(1000)

        // Step 3: Update sync metadata
        Log.d(TAG, "[$taskId] Updating sync metadata")
        val prefs = getSharedPreferences("sync_metadata", Context.MODE_PRIVATE)
        prefs.edit()
            .putLong("last_incremental_sync", System.currentTimeMillis())
            .putString("last_sync_task_id", taskId)
            .apply()

        Log.d(TAG, "[$taskId] Incremental sync completed")
    }

    private fun performFullSync(taskId: String) {
        Log.d(TAG, "[$taskId] Performing full sync...")

        // Step 1: Clear existing sync state
        Log.d(TAG, "[$taskId] Clearing existing sync state")
        simulateWork(300)

        // Step 2: Download all configuration data
        Log.d(TAG, "[$taskId] Downloading all configuration data")
        simulateWork(2000)

        // Step 3: Rebuild local data store
        Log.d(TAG, "[$taskId] Rebuilding local data store")
        simulateWork(1500)

        // Step 4: Verify data integrity
        Log.d(TAG, "[$taskId] Verifying data integrity")
        simulateWork(500)

        // Step 5: Update sync metadata
        Log.d(TAG, "[$taskId] Updating sync metadata")
        val prefs = getSharedPreferences("sync_metadata", Context.MODE_PRIVATE)
        prefs.edit()
            .putLong("last_full_sync", System.currentTimeMillis())
            .putString("last_sync_task_id", taskId)
            .apply()

        Log.d(TAG, "[$taskId] Full sync completed")
    }

    private fun processCleanup(intent: Intent, taskId: String) {
        val cleanupLevel = intent.getIntExtra(EXTRA_CLEANUP_LEVEL, CLEANUP_LEVEL_LIGHT)
        val maxAgeDays = intent.getIntExtra(EXTRA_MAX_AGE_DAYS, 30)
        val targetDirectories = intent.getStringArrayExtra(EXTRA_TARGET_DIRECTORIES)

        Log.i(TAG, "Starting cleanup - Level: $cleanupLevel, MaxAge: $maxAgeDays days, TaskId: $taskId")
        updateNotification("Running cleanup (level $cleanupLevel)...")

        when (cleanupLevel) {
            CLEANUP_LEVEL_LIGHT -> performLightCleanup(taskId, maxAgeDays)
            CLEANUP_LEVEL_MODERATE -> performModerateCleanup(taskId, maxAgeDays, targetDirectories)
            CLEANUP_LEVEL_DEEP -> performDeepCleanup(taskId, maxAgeDays, targetDirectories)
        }

        Log.i(TAG, "Cleanup completed for task: $taskId")
    }

    private fun performLightCleanup(taskId: String, maxAgeDays: Int) {
        Log.d(TAG, "[$taskId] Performing light cleanup...")

        // Clean expired cache files
        val cacheDir = cacheDir
        val cutoffTime = System.currentTimeMillis() - (maxAgeDays.toLong() * 24 * 60 * 60 * 1000)
        var cleanedCount = 0
        var cleanedSize = 0L

        cacheDir.listFiles()?.forEach { file ->
            if (file.isFile && file.lastModified() < cutoffTime) {
                val fileSize = file.length()
                if (file.delete()) {
                    cleanedCount++
                    cleanedSize += fileSize
                    Log.d(TAG, "[$taskId] Deleted cache file: ${file.name}")
                }
            }
        }

        Log.d(TAG, "[$taskId] Light cleanup completed: $cleanedCount files, ${cleanedSize / 1024} KB freed")

        // Record cleanup stats
        recordCleanupStats(taskId, "light", cleanedCount, cleanedSize)
    }

    private fun performModerateCleanup(taskId: String, maxAgeDays: Int, targetDirectories: Array<String>?) {
        Log.d(TAG, "[$taskId] Performing moderate cleanup...")

        // First do light cleanup
        performLightCleanup(taskId, maxAgeDays)

        // Clean temporary files in target directories
        val dirsToClean = targetDirectories?.map { java.io.File(it) }
            ?: listOf(cacheDir, filesDir)

        var totalCleaned = 0
        var totalSize = 0L
        val cutoffTime = System.currentTimeMillis() - (maxAgeDays.toLong() * 24 * 60 * 60 * 1000)

        for (dir in dirsToClean) {
            if (!dir.exists() || !dir.isDirectory) continue

            // Verify the directory is within allowed scope
            if (!isPathWithinAllowedScope(dir.absolutePath)) {
                Log.w(TAG, "[$taskId] Skipping directory outside allowed scope: ${dir.absolutePath}")
                continue
            }

            dir.listFiles()?.forEach { file ->
                if (file.isFile && file.lastModified() < cutoffTime) {
                    // Only clean known temporary file extensions
                    if (file.extension in setOf("tmp", "temp", "log", "bak")) {
                        val fileSize = file.length()
                        if (file.delete()) {
                            totalCleaned++
                            totalSize += fileSize
                        }
                    }
                }
            }
        }

        Log.d(TAG, "[$taskId] Moderate cleanup completed: $totalCleaned additional files, ${totalSize / 1024} KB freed")
        recordCleanupStats(taskId, "moderate", totalCleaned, totalSize)
    }

    private fun performDeepCleanup(taskId: String, maxAgeDays: Int, targetDirectories: Array<String>?) {
        Log.d(TAG, "[$taskId] Performing deep cleanup...")

        // First do moderate cleanup
        performModerateCleanup(taskId, maxAgeDays, targetDirectories)

        // Clean database WAL files
        Log.d(TAG, "[$taskId] Cleaning database WAL files")
        simulateWork(500)

        // Compact shared preferences
        Log.d(TAG, "[$taskId] Compacting shared preferences")
        simulateWork(300)

        // Clean old log files
        val logDir = java.io.File(filesDir, "logs")
        if (logDir.exists() && logDir.isDirectory) {
            val cutoffTime = System.currentTimeMillis() - (maxAgeDays.toLong() * 24 * 60 * 60 * 1000)
            var logsCleaned = 0

            logDir.listFiles()?.forEach { file ->
                if (file.isFile && file.lastModified() < cutoffTime) {
                    if (file.delete()) {
                        logsCleaned++
                    }
                }
            }
            Log.d(TAG, "[$taskId] Cleaned $logsCleaned old log files")
        }

        // Clean old sync metadata
        Log.d(TAG, "[$taskId] Cleaning old sync metadata")
        simulateWork(200)

        Log.d(TAG, "[$taskId] Deep cleanup completed")
        recordCleanupStats(taskId, "deep", 0, 0)
    }

    private fun processFullMaintenance(intent: Intent, taskId: String) {
        Log.i(TAG, "Starting full maintenance for task: $taskId")
        updateNotification("Running full maintenance...")

        // Step 1: Data sync
        Log.d(TAG, "[$taskId] Full maintenance - Step 1: Data sync")
        processSyncData(intent, "$taskId-sync")

        // Step 2: Cleanup
        Log.d(TAG, "[$taskId] Full maintenance - Step 2: Cleanup")
        processCleanup(intent, "$taskId-cleanup")

        // Step 3: Optimization
        Log.d(TAG, "[$taskId] Full maintenance - Step 3: Optimization")
        updateNotification("Optimizing...")
        performOptimization(taskId)

        Log.i(TAG, "Full maintenance completed for task: $taskId")
    }

    private fun performOptimization(taskId: String) {
        Log.d(TAG, "[$taskId] Running optimization routines...")

        // Defragment internal data structures
        Log.d(TAG, "[$taskId] Defragmenting data structures")
        simulateWork(1000)

        // Rebuild indexes
        Log.d(TAG, "[$taskId] Rebuilding indexes")
        simulateWork(800)

        // Update optimization timestamp
        val prefs = getSharedPreferences("optimization_metadata", Context.MODE_PRIVATE)
        prefs.edit()
            .putLong("last_optimization", System.currentTimeMillis())
            .putString("last_optimization_task_id", taskId)
            .apply()

        Log.d(TAG, "[$taskId] Optimization completed")
    }

    // --- Helper Methods ---

    private fun recordCleanupStats(taskId: String, level: String, filesCount: Int, bytesFreed: Long) {
        val prefs = getSharedPreferences("cleanup_stats", Context.MODE_PRIVATE)
        prefs.edit()
            .putLong("last_cleanup_time", System.currentTimeMillis())
            .putString("last_cleanup_task_id", taskId)
            .putString("last_cleanup_level", level)
            .putInt("last_cleanup_files_count", filesCount)
            .putLong("last_cleanup_bytes_freed", bytesFreed)
            .apply()
    }

    private fun sanitizeString(input: String): String {
        // Remove any potentially dangerous characters
        return input.replace(Regex("[^a-zA-Z0-9_\\-.]"), "")
    }

    private fun generateTaskId(): String {
        return "task_${System.currentTimeMillis()}_${(Math.random() * 10000).toInt()}"
    }

    private fun simulateWork(durationMs: Long) {
        try {
            Thread.sleep(durationMs)
        } catch (e: InterruptedException) {
            Thread.currentThread().interrupt()
            Log.w(TAG, "Work simulation interrupted")
        }
    }

    private fun stopSelfIfIdle(startId: Int) {
        synchronized(taskLock) {
            if (activeTasks.isEmpty()) {
                isRunning.set(false)
                stopForeground(true)
                stopSelf(startId)
            }
        }
    }

    // --- Notification Management ---

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Task Processor",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background task processing notifications"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun buildNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = buildNotification(contentText)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    // --- Callback Methods ---

    private fun sendSuccessCallback(originalIntent: Intent, taskId: String) {
        val callbackAction = originalIntent.getStringExtra(EXTRA_CALLBACK_ACTION) ?: return

        try {
            val callbackIntent = Intent(callbackAction).apply {
                putExtra("result_status", "SUCCESS")
                putExtra("task_id", taskId)
                putExtra("completion_time", System.currentTimeMillis())
                setPackage(getCallerPackageFromIntent(originalIntent))
            }
            sendBroadcast(callbackIntent, "com.example.systemoptimizer.permission.RECEIVE_TASK_RESULT")
            Log.d(TAG, "Success callback sent for task: $taskId")
        } catch (e: Exception) {
            Log.e(TAG, "Failed to send success callback for task: $taskId", e)
        }
    }

    private fun sendErrorCallback(originalIntent: Intent, errorCode: String, errorMessage: String) {
        val callbackAction = originalIntent.getStringExtra(EXTRA_CALLBACK_ACTION) ?: return

        try {
            val callbackIntent = Intent(callbackAction).apply {
                putExtra("result_status", "ERROR")
                putExtra("error_code", errorCode)
                putExtra("error_message", errorMessage)
                putExtra("completion_time", System.currentTimeMillis())
                setPackage(getCallerPackageFromIntent(originalIntent))
            }
            sendBroadcast(callbackIntent, "com.example.systemoptimizer.permission.RECEIVE_TASK_RESULT")
            Log.d(TAG, "Error callback sent: $errorCode - $errorMessage")
        } catch (e: Exception) {
            Log.e(TAG, "Failed to send error callback", e)
        }
    }

    private fun getCallerPackageFromIntent(intent: Intent): String? {
        val callingUid = android.os.Binder.getCallingUid()
        return getCallingPackageName(callingUid)
    }
}